export default PaymentModule;

export function PaymentButton({
  sku,
  title = 'Buy',
  style,
  textStyle,
  onSuccess,
  onError,
  disabled,
}) {
  const [loading, setLoading] = useState(false);

  const onPress = useCallback(async () => {
    try {
      setLoading(true);
      await PaymentModule.requestPurchase({ sku });
      onSuccess && onSuccess();
    } catch (e) {
      onError && onError(e);
      if (e?.code !== PaymentErrorCodes.CANCELED) {
        Alert.alert('Payment Error', e?.message || 'Payment failed');
      }
    } finally {
      setLoading(false);
    }
  }, [sku, onSuccess, onError]);

  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      style={[
        { padding: 12, backgroundColor: '#111', borderRadius: 10, opacity: disabled || loading ? 0.6 : 1 },
        style,
      ]}
    >
      {loading ? (
        <ActivityIndicator color="#fff" />
      ) : (
        <Text style={[{ color: '#fff', textAlign: 'center', fontWeight: '600' }, textStyle]}>{title}</Text>
      )}
    </TouchableOpacity>
  );
}

export function WalletTransferButton({
  amountCents,
  currency = 'USD',
  title = 'Pay',
  metadata,
  customerId,
  style,
  textStyle,
  onSuccess,
  onError,
  disabled,
}) {
  const [loading, setLoading] = useState(false);

  const onPress = useCallback(async () => {
    try {
      setLoading(true);
      const id = await PaymentModule.createWalletTransaction({
        amountCents,
        currency,
        type: 'debit',
        source: 'wallet',
        metadata: metadata || {},
        customerId,
      });
      onSuccess && onSuccess(id);
    } catch (e) {
      onError && onError(e);
      if (e?.code !== PaymentErrorCodes.CANCELED) {
        Alert.alert('Payment Error', e?.message || 'Transaction failed');
      }
    } finally {
      setLoading(false);
    }
  }, [amountCents, currency, metadata, customerId, onSuccess, onError]);

  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      style={[
        { padding: 12, backgroundColor: '#0b5', borderRadius: 10, opacity: disabled || loading ? 0.6 : 1 },
        style,
      ]}
    >
      {loading ? (
        <ActivityIndicator color="#fff" />
      ) : (
        <Text style={[{ color: '#fff', textAlign: 'center', fontWeight: '600' }, textStyle]}>{title}</Text>
      )}
    </TouchableOpacity>
  );
}

export function PaymentStatusPanel({ style }) {
  const state = PaymentModule.usePaymentStore((s) => ({
    ready: s.ready,
    iapConnected: s.iapConnected,
    lastSyncAt: s.lastSyncAt,
    pendingWalletTx: s.pendingWalletTx,
    pendingIapReceipts: s.pendingIapReceipts,
    adoptionStage: s.adoptionStage,
  }));

  return (
    <View style={[{ padding: 12, borderWidth: 1, borderColor: '#ddd', borderRadius: 12 }, style]}>
      <Text style={{ fontWeight: '700', marginBottom: 8 }}>Payment Module</Text>
      <Text>Ready: {String(state.ready)}</Text>
      <Text>IAP Connected: {String(state.iapConnected)}</Text>
      <Text>Catalog Synced At: {state.lastSyncAt || '-'}</Text>
      <Text>Pending Wallet TX: {state.pendingWalletTx.length}</Text>
      <Text>Pending IAP Receipts: {state.pendingIapReceipts.length}</Text>
      <Text>Security Stage: {state.adoptionStage}</Text>
      <TouchableOpacity
        onPress={() => PaymentModule.flushPending().catch(() => {})}
        style={{ marginTop: 10, padding: 10, backgroundColor: '#222', borderRadius: 10 }}
      >
        <Text style={{ color: '#fff', textAlign: 'center' }}>Retry Pending</Text>
      </TouchableOpacity>
    </View>
  );
}